List<Subject> getCambridgeSubjectsForGrade(String grade) {
  return cambridgeCurriculumByGrade[grade] ?? [];
}

List<Subject> getAllCambridgeSubjects() {
  return cambridgeCurriculumByGrade.values.expand((list) => list).toList();
}

List<String> getCambridgeGradeLevels() {
  return cambridgeCurriculumByGrade.keys.toList();
}

List<Topic> getCambridgeTopicsForSubject(String subjectId, String gradeLevel) {
  return _cambridgeTopics.where((t) => t.subjectId == subjectId && t.gradeLevel == gradeLevel).toList();
}

